import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';

interface RCA {
  _id: string;
  title: string;
  description: string;
  severity: string;
  status: string;
  reviews: { reviewer: string; decision: string; comment: string }[];
  createdAt: string;
}

const RCA: React.FC = () => {
  const { projectId } = useParams<{ projectId: string }>();
  const navigate = useNavigate();
  const [rcas, setRcas] = useState<RCA[]>([]);
  const [newRCA, setNewRCA] = useState({ 
    title: '', 
    description: '', 
    severity: 'medium' 
  });
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    if (projectId) {
      fetchRCAs();
    } else {
      setError('No project ID provided');
      setLoading(false);
    }
  }, [projectId]);

  const fetchRCAs = async () => {
    try {
      const token = localStorage.getItem('token');
      if (!token) {
        setError('Please login first');
        setLoading(false);
        return;
      }

      const response = await fetch(`http://localhost:5000/api/rca/project/${projectId}`, {
        headers: { 'Authorization': `Bearer ${token}` }
      });
      
      if (response.ok) {
        const data = await response.json();
        setRcas(data.data || []);
      } else {
        setError('Failed to fetch RCAs');
      }
    } catch (error) {
      console.error('Error fetching RCAs:', error);
      setError('Error connecting to server');
    } finally {
      setLoading(false);
    }
  };

  const createRCA = async () => {
    if (!newRCA.title.trim()) {
      window.alert('Please enter a title');
      return;
    }
    
    try {
      const token = localStorage.getItem('token');
      const user = JSON.parse(localStorage.getItem('user') || '{}');
      
      const response = await fetch('http://localhost:5000/api/rca', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`
        },
        body: JSON.stringify({ 
          ...newRCA, 
          projectId,
          reportedBy: user._id
        })
      });
      
      if (response.ok) {
        setNewRCA({ title: '', description: '', severity: 'medium' });
        fetchRCAs();
      } else {
        const data = await response.json();
        window.alert(data.message || 'Failed to create RCA');
      }
    } catch (error) {
      console.error('Error creating RCA:', error);
      window.alert('Error creating RCA');
    }
  };

  const getSeverityColor = (severity: string) => {
    const colors: { [key: string]: string } = {
      critical: '#dc3545',
      high: '#fd7e14',
      medium: '#ffc107',
      low: '#6c757d'
    };
    return colors[severity] || '#6c757d';
  };

  const getStatusColor = (status: string) => {
    const colors: { [key: string]: string } = {
      reported: '#6c757d',
      investigating: '#0066cc',
      in_review: '#ffc107',
      approved: '#28a745',
      rejected: '#dc3545',
      closed: '#17a2b8'
    };
    return colors[status] || '#6c757d';
  };

  if (loading) {
    return (
      <div style={styles.loading}>
        <div style={styles.spinner}></div>
        <p>Loading RCAs...</p>
      </div>
    );
  }

  if (error) {
    return (
      <div style={styles.errorContainer}>
        <h2>❌ Error</h2>
        <p>{error}</p>
        <button onClick={() => navigate('/dashboard')} style={styles.errorBtn}>
          Go to Dashboard
        </button>
      </div>
    );
  }

  return (
    <div style={styles.container}>
      <div style={styles.header}>
        <button onClick={() => navigate(`/project/${projectId}`)} style={styles.backBtn}>
          ← Back to Project
        </button>
        <h1 style={styles.title}>🔍 Root Cause Analysis</h1>
      </div>

      {/* Create RCA Form */}
      <div style={styles.createSection}>
        <h3 style={styles.sectionTitle}>Report New Incident</h3>
        <div style={styles.form}>
          <input
            placeholder="Incident Title *"
            value={newRCA.title}
            onChange={(e) => setNewRCA({ ...newRCA, title: e.target.value })}
            style={styles.input}
          />
          <textarea
            placeholder="Description"
            value={newRCA.description}
            onChange={(e) => setNewRCA({ ...newRCA, description: e.target.value })}
            style={styles.textarea}
          />
          <select
            value={newRCA.severity}
            onChange={(e) => setNewRCA({ ...newRCA, severity: e.target.value })}
            style={styles.select}
          >
            <option value="critical">🔴 Critical</option>
            <option value="high">🟠 High</option>
            <option value="medium">🟡 Medium</option>
            <option value="low">🟢 Low</option>
          </select>
          <button onClick={createRCA} style={styles.createBtn}>
            Report Incident
          </button>
        </div>
      </div>

      {/* RCA List */}
      <div style={styles.list}>
        {rcas.length === 0 ? (
          <div style={styles.emptyState}>
            <p>No incidents reported yet.</p>
          </div>
        ) : (
          rcas.map((rca) => (
            <div key={rca._id} style={styles.card}>
              <div style={styles.cardHeader}>
                <h3 style={styles.cardTitle}>{rca.title}</h3>
                <span style={{
                  ...styles.severityBadge,
                  backgroundColor: getSeverityColor(rca.severity)
                }}>
                  {rca.severity}
                </span>
              </div>
              
              <p style={styles.cardDesc}>{rca.description}</p>
              
              <div style={styles.cardFooter}>
                <span style={{
                  ...styles.statusBadge,
                  backgroundColor: getStatusColor(rca.status || 'reported')
                }}>
                  {rca.status || 'reported'}
                </span>
                <span style={styles.reviewCount}>
                  📝 Reviews: {rca.reviews?.length || 0}
                </span>
                <span style={styles.date}>
                  📅 {new Date(rca.createdAt).toLocaleDateString()}
                </span>
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

const styles: { [key: string]: React.CSSProperties } = {
  container: {
    padding: '30px',
    maxWidth: '1200px',
    margin: '0 auto',
    minHeight: 'calc(100vh - 200px)'
  },
  header: {
    display: 'flex',
    alignItems: 'center',
    gap: '20px',
    marginBottom: '30px'
  },
  backBtn: {
    background: 'none',
    border: 'none',
    color: '#0066cc',
    fontSize: '16px',
    cursor: 'pointer',
    padding: '8px 16px',
    borderRadius: '4px',
    backgroundColor: '#e9ecef'
  },
  title: {
    fontSize: '28px',
    color: '#1a1a2e',
    margin: 0
  },
  loading: {
    display: 'flex',
    flexDirection: 'column' as 'column',
    justifyContent: 'center',
    alignItems: 'center',
    minHeight: '50vh',
    fontSize: '18px',
    color: '#666'
  },
  spinner: {
    width: '40px',
    height: '40px',
    border: '4px solid #e9ecef',
    borderTop: '4px solid #0066cc',
    borderRadius: '50%',
    animation: 'spin 1s linear infinite',
    marginBottom: '20px'
  },
  errorContainer: {
    display: 'flex',
    flexDirection: 'column' as 'column',
    justifyContent: 'center',
    alignItems: 'center',
    minHeight: '50vh',
    color: '#dc3545'
  },
  errorBtn: {
    marginTop: '20px',
